window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q11"]=window.__LIBQ["tien-nghich"]["q11"]||{};window.__LIBQ["tien-nghich"]["q11"]["artifacts"]={"updatedAt":"2026-07-12","count":69,"artifacts":[{"id":"ngoc-boi-menh-hon-ly-thien-mai","name":"Ngọc bội mệnh hồn","cn":null,"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lý Thiến Mai"],"trangThai":"Đặt trên tượng đá Vương Lâm, ánh sáng dần mờ, xuất hiện khe nứt","blurb":"Ngọc bội chứa mệnh hồn của Lý Thiến Mai, được nàng đặt lên tượng đá Vương Lâm trước khi rời sơn cốc để duy trì sinh cơ cho tượng.","detail":"Lý Thiến Mai đặt ngọc bội mệnh hồn lên tượng đá Vương Lâm vào tháng thứ chín của năm thứ mười, khi đạo huyết nguyên thần cũng không còn đủ cung ứng. Ngọc bội tỏa ánh sáng nhu hòa, có thể duy trì tượng đá khoảng một tháng. Khi ba tháng trôi qua mà Lý Thiến Mai không trở về, ánh sáng ngọc bội dần mờ và xuất hiện khe nứt nhỏ, ám chỉ mệnh hồn nàng đang suy yếu nghiêm trọng.","nguon":["@c1214"]},{"id":"hon-huyet-ly-thien-mai","name":"Hồn huyết Lý Thiến Mai","cn":null,"category":"khac","categoryLabel":"Vật phẩm đặc thù","phamCap":"Không rõ","soHuu":["Lý Thiến Mai"],"trangThai":"Đã dung nhập tượng đá Vương Lâm, giúp hắn thức tỉnh","blurb":"Trái cầu máu cỡ nắm tay, thực chất là một phần hồn phách ngưng tụ, được Yêu Tông lấy trước khi tu sĩ ra chiến trường để dùng chuyển thế trọng tu nếu tử vong.","detail":"Hồn huyết không phải máu chính thức mà là một phần hồn phách ngưng tụ lại. Yêu Tông thu lấy hồn huyết từ các tu sĩ được coi trọng trước khi ra chiến trường, nếu tu sĩ tử vong thì dùng hồn huyết để chuyển thế trọng tu. Lý Thiến Mai muốn thu hồi hồn huyết bản thân để cứu Vương Lâm, phải đáp ứng điều kiện Yêu Tông — đi vào khe sâu nhất chiến trường dò xét thông đạo giới ngoại, gần như tử lộ. Bà lão bạch y (sư tỷ Lý Thiến Mai) mang hồn huyết tới sơn cốc, dung nhập vào tượng đá. Huyết quang tỏa ra mang sinh cơ và sự ôn nhu mười năm của Lý Thiến Mai, khiến Vương Lâm lần đầu mở mắt sau mười năm hôn mê.","nguon":["@c1214"]},{"id":"ngon-nui-thanh-kiem-co-than","name":"Ngọn núi thanh kiếm Cổ Thần (pháp khí Cổ Thần cửu tinh)","aliases":["Pháp khí Cổ Thần cửu tinh"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Pháp khí Cổ Thần cửu tinh","soHuu":["Vương Lâm"],"trangThai":"Đang bị Vương Lâm đoạt từ Vô Cực Tông","blurb":"Ngọn núi hùng vĩ tại sơn môn Vô Cực Tông do thanh kiếm Cổ Thần hóa thành, bên trong phong ấn pho tượng Cổ Thần giãy giụa gào thét. Chứa Cổ Thần lực chí cường, khi được kích hoạt truyền Cổ Thần lực cho người có huyết mạch Cổ Thần.","detail":"Ngọn núi do thanh kiếm Cổ Thần hóa thành, vốn không thuộc Vô Cực Tông. Khi Vương Lâm kích hoạt Cổ Thần lực, núi phát ra khí tức tang thương kinh thiên, nứt vỡ, bên trong hiện pho tượng Cổ Thần lờ mờ mở mắt giãy giụa gào thét muốn thoát khốn. Cổ Thần lực từ núi liên tục chảy vào thân Vương Lâm, khiến hắn tái hiện bốn Cổ Thần tinh điểm trên mi tâm.","congNang":["Chứa Cổ Thần lực chí cường, truyền Cổ Thần lực cho người có huyết mạch Cổ Thần","Bên trong phong ấn pho tượng Cổ Thần"],"hinhDang":"Ngọn núi hùng vĩ do thanh kiếm Cổ Thần hóa thành","nguonGoc":"Vốn không thuộc Vô Cực Tông, do thanh kiếm Cổ Thần biến hóa","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vô Cực Tông","tuChuong":"@c1217","denChuong":"@c1217","cachCoDuoc":"Phong ấn sẵn tại sơn môn","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1217","denChuong":"","cachCoDuoc":"Dùng Cổ Thần lực kích hoạt và đoạt lấy","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1217","loai":"đổi chủ","importance":"major","giaiDoan":"Vương Lâm đoạt từ Vô Cực Tông","text":"Vương Lâm kích hoạt Cổ Thần lực bên trong ngọn núi, Cổ Thần lực chảy vào thân thể hắn, mi tâm tái hiện bốn Cổ Thần tinh điểm. Núi nứt vỡ, pho tượng Cổ Thần bên trong giãy giụa gào thét. Vô Cực Tông huy động sáu cường giả và bốn thái tổ trưởng lão ngăn cản nhưng bất thành.","anchor":"Đó là thứ hắn hoài nghi là pháp khí của Cổ Thần cửu tinh"}]},"capNhatToi":"@c1217","nguon":["@c1217"]},{"id":"ky-hieu-huyet-sac-vuong-lam","name":"Ký hiệu huyết sắc (huyết thệ Vương Lâm)","category":"khac","categoryLabel":"Vật phẩm","soHuu":["Vương Lâm"],"trangThai":"hong","blurb":"Ký hiệu huyết sắc do Vương Lâm cắn lưỡi phun máu tạo ra, chứa một tia hồn phách, dùng làm tín vật huyết thệ gửi tông chủ Vô Cực Tông. Bị hắc y lão giả chụp nát.","detail":"Vương Lâm cắn chót lưỡi phun máu hóa thành ký hiệu huyết sắc chứa một tia hồn phách, gửi cho tông chủ Vô Cực Tông làm tín vật thề sẽ trả lại pháp khí. Khi bị hắc y lão giả chụp nát, ký hiệu sụp đổ, Vương Lâm sắc mặt tái nhợt.","congNang":["Chứa máu và hồn phách chủ nhân, làm tín vật huyết thệ"],"nguon":["@c1217"]},{"id":"ban-menh-phap-bao-dai-thu-yeu-tong","name":"Bản mệnh pháp bảo đại thụ (tông chủ Yêu Tông)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Tông chủ đời đầu Yêu Tông"],"trangThai":"khong-ro","blurb":"Cây đại thụ cao chọc trời, là bản mệnh pháp bảo của tông chủ đời đầu Yêu Tông, hình ảnh được khắc trên sáu bia đá trong sáu sơn môn.","detail":"Bản mệnh pháp bảo của tông chủ Yêu Tông, có hình dạng cây đại thụ lớn đến mức cả đất trời không thể ngăn cản. Hình ảnh cây đại thụ đứng phía sau tông chủ được khắc trên sáu tấm bia đá chọc trời trong sáu sơn môn Yêu Tông.","hinhDang":"Cây đại thụ cao chọc trời","tabs":{"tienTrinh":[{"chuong":"@c1221","loai":"nhắc tới","importance":"normal","giaiDoan":"Hé lộ qua bia đá","text":"Hình ảnh bản mệnh pháp bảo đại thụ của tông chủ được khắc trên sáu bia đá trong sáu sơn môn Yêu Tông.","anchor":"cây đại thụ kia là bản mệnh pháp bảo của tông chủ Yêu Tông"}]},"nguon":["@c1221"]},{"id":"huyet-kiem-mau-co-than","name":"Huyết kiếm (máu Cổ Thần)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Giọt máu tươi từ mi tâm Vương Lâm hóa thành thanh huyết kiếm toàn thân đỏ như máu, uy lực phá nát pháp bảo tu sĩ Thiên Nhân Đệ Nhị Suy, có thể dung nhập vào thân biến người thành kiếm.","detail":"Huyết kiếm hóa từ giọt máu Cổ Thần trên mi tâm Vương Lâm, toàn thân đỏ như máu. Chém nát pháp bảo mai rùa của trưởng lão Yêu Tông rồi xuyên vào thân thể hắn. Vương Lâm có thể thu kiếm dung nhập vào cơ thể, hóa toàn thân thành huyết kiếm — bản thân chính là kiếm.","congNang":["Hóa từ máu mi tâm Cổ Thần, chém phá pháp bảo","Có thể dung nhập vào thân, biến người thành kiếm"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1222","denChuong":"","cachCoDuoc":"Hóa từ máu Cổ Thần trên mi tâm","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1222","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Giọt máu từ mi tâm Vương Lâm hóa thành huyết kiếm đỏ, chém nát mai rùa pháp bảo trưởng lão Yêu Tông, xuyên vào thân đối thủ. Sau đó dung nhập vào cơ thể Vương Lâm, hóa toàn thân thành kiếm.","anchor":"từ trong mi tâm bay ra một giọt máu tươi, hóa thành một thanh huyết kiếm toàn thân đỏ như máu"}]},"nguon":["@c1222"]},{"id":"mai-rua-phap-bao-truong-lao-yeu-tong","name":"Mai rùa (pháp bảo trưởng lão Yêu Tông)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Trưởng lão Yêu Tông"],"trangThai":"hong","blurb":"Pháp bảo phòng ngự của trưởng lão Yêu Tông, bấm quyết phun ra để chắn huyết kiếm nhưng bị chém nứt rồi tan vỡ.","detail":"Tấm mai rùa được trưởng lão Yêu Tông bấm quyết phun ra để phòng ngự trước huyết kiếm Vương Lâm, nhưng không chống nổi uy lực, vết nứt nổ tung và tan vỡ.","congNang":["Phòng ngự"],"chuSoHuu":[{"ten":"Trưởng lão Yêu Tông","tuChuong":"@c1222","denChuong":"@c1222","cachCoDuoc":"","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c1222","loai":"hư tổn/tu bổ","importance":"normal","giaiDoan":"Bị phá hủy","text":"Bấm quyết phun ra chắn huyết kiếm Vương Lâm nhưng bị chém nứt rồi tan vỡ hoàn toàn.","anchor":"tấm mai rùa kia hiển nhiên không thể ngăn cản được uy lực của thanh huyết kiếm, vết nứt trên đó nổ tung"}]},"nguon":["@c1222"]},{"id":"truong-kiem-nu-tu-ao-lam","name":"Trường kiếm của nữ tử áo lam","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lý Thiến Mai"],"trangThai":"khong-ro","blurb":"Thanh trường kiếm xuất hiện trong tay nữ tử áo lam (nghi là Lý Thiến Mai) qua ảo ảnh quá khứ tại khe nứt Tử Giới.","detail":"Xuất hiện trong ảo ảnh quá khứ khi Vương Lâm thi triển Tuế Nguyệt Nghịch Chuyển: nữ tử áo lam sắc mặt nhợt nhạt, quần áo nhuốm máu, tay cầm thanh trường kiếm, đang nhanh chóng bay đi trong hư vô.","nguon":["@c1223"]},{"id":"but-mau-vang-nu-tu-ao-lam","name":"Bút màu vàng","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Lý Thiến Mai"],"trangThai":"khong-ro","blurb":"Chiếc bút màu vàng vờn quanh bên ngoài thân thể nữ tử áo lam trong ảo ảnh quá khứ tại khe nứt Tử Giới.","detail":"Xuất hiện trong ảo ảnh quá khứ: chiếc bút màu vàng vờn quanh bên ngoài thân thể nữ tử áo lam (nghi là Lý Thiến Mai) khi nàng đang bị thương và bay đi.","nguon":["@c1223"]},{"id":"hu-anh-chiec-roi","name":"Hư ảnh chiếc roi","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Roi khổng lồ dạng hư ảnh tấn công bên trong khe nứt thế giới tím, chứa sức mạnh kỳ dị vượt qua quy tắc, bị phá hủy nhưng lại tái xuất hiện.","detail":"Hư ảnh chiếc roi khổng lồ quất vỡ lam quang bảo hộ trên thân Lý Thiến Mai, chứa sức mạnh kỳ dị mà ngay cả quy tắc Định Thân Thuật cũng không thể ngăn cản. Bị Vương Lâm kích phát sức mạnh Cổ Thần phá hủy, nhưng sau đó lại xuất hiện thêm hai hư ảnh chiếc roi mới tiếp tục tấn công. Nguồn gốc và chủ nhân chưa rõ.","congNang":["Tấn công phá vỡ quy tắc và lam quang bảo hộ","Tái sinh sau khi bị phá hủy, xuất hiện nhiều chiếc mới"],"nguon":["@c1225"]},{"id":"hai-hu-anh-chiec-roi","name":"Hai hư ảnh chiếc roi","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":[],"trangThai":"da-huy","blurb":"Hai hư ảnh chiếc roi lóe lên gào thét từ hư vô tối đen, tấn công Vương Lâm khi phong ấn sụp đổ. Cả hai đều bị phá hủy hoàn toàn.","detail":"Hai chiếc roi xuất hiện từ hư vô tối đen bên trong khe nứt, lao tới tấn công Vương Lâm ngay khi phong ấn cấm chế sụp đổ. Chiếc thứ nhất bị lốc xoáy nguyên lực đánh vỡ tan. Chiếc thứ hai bị Vương Lâm tay trái túm lấy, sau đó ném đi kèm huyết kiếm phá hủy trong hư vô — khi vỡ có tiếng kêu rên từ hư vô truyền ra, gợi ý có thực thể bí ẩn ẩn trong hư vô.","congNang":["Tấn công từ hư vô tối đen, lao tới mục tiêu gào thét"],"nguon":["@c1226"],"tabs":{"tienTrinh":[{"chuong":"@c1226","loai":"xuất hiện","importance":"major","giaiDoan":"Xuất hiện và bị phá hủy","text":"Hai hư ảnh chiếc roi lóe lên từ hư vô tối đen tấn công Vương Lâm khi phong ấn sụp đổ. Chiếc thứ nhất bị lốc xoáy đánh vỡ, chiếc thứ hai bị Vương Lâm túm rồi phun huyết kiếm phá hủy, tiếng kêu rên từ hư vô truyền ra.","anchor":"hai hư ảnh chiếc roi lóe lên gào thét bên trong hư vô tối đen"}]}},{"id":"chin-duoi-bo-cap-dung-hop","name":"Chín đuôi bọ cạp dung hợp","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đang giữ","blurb":"Chín chiếc đuôi bọ cạp cấp mười ba được Vương Lâm dùng nguyên khí hóa lửa lam thiêu đốt rồi cấm chế dung hợp thành một.","detail":"Vương Lâm giật chín đuôi bọ cạp cấp mười ba Tử Huyết, dùng nguyên khí hóa lửa lam thiêu đốt, hạ cấm chế dung hợp chín đuôi thành một rồi thu vào trữ vật.","congNang":["Chưa rõ công dụng cụ thể, vật liệu từ mãnh thú cấp mười ba"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1228","denChuong":"","cachCoDuoc":"Thu từ bọ cạp cấp mười ba bị tiêu diệt","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1228","loai":"xuat-hien","importance":"normal","giaiDoan":"Vương Lâm thu hoạch","text":"Vương Lâm giật chín đuôi bọ cạp cấp mười ba, dùng lửa lam thiêu đốt rồi cấm chế dung hợp thành một, thu vào trữ vật.","anchor":"chín chiếc đuôi bọ cạp dung hợp làm một, bị Vương Lâm thu vào trong khe nứt trữ vật"}]},"nguon":["@c1228"]},{"id":"hac-dan-bo-cap","name":"Hắc đan bọ cạp","cn":"","category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đang giữ","blurb":"Viên đan đen lớn bằng nắm tay trong đầu bọ cạp cấp mười ba, chứa nguyên thần nữ tử hóa hình.","detail":"Mãnh thú cấp mười ba hóa hình người có thể bảo tồn nguyên thần trong hắc đan khi thú thể bị diệt. Vương Lâm đập vỡ đầu bọ cạp Tử Huyết, lộ ra hắc đan, dùng thần thức xâm nhập lục soát ký ức.","congNang":["Chứa nguyên thần mãnh thú cấp mười ba hóa hình"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1228","denChuong":"","cachCoDuoc":"Đập vỡ đầu bọ cạp cấp mười ba","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1228","loai":"xuat-hien","importance":"normal","giaiDoan":"Vương Lâm thu hoạch","text":"Vương Lâm đập vỡ đầu bọ cạp, lộ ra hắc đan lớn bằng nắm tay chứa nguyên thần, dùng thần thức lục soát ký ức.","anchor":"lộ ra một hắc đan lớn bằng nắm tay"}]},"nguon":["@c1228"]},{"id":"ngoc-boi-truyen-tong-khe-nut","name":"Ngọc bội truyền tống khe nứt","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đang giữ","blurb":"Ngọc bội chứa truyền tống trận phức tạp, cho phép từ bất kỳ đâu vào khe nứt và ngược lại. Y Nguyệt trao cho Vương Lâm.","detail":"Y Nguyệt trao cho Vương Lâm ngọc bội chứa truyền tống trận rất phức tạp, có thể từ bất kỳ nơi đâu vào trong khe nứt, cũng có thể từ khe nứt ra ngoài miệng khe. Vương Lâm kiểm tra bằng thần niệm, xác nhận trận pháp phức tạp không nhìn ra manh mối nhưng an toàn, rồi dùng để rời đi.","congNang":["Truyền tống hai chiều giữa bất kỳ đâu và khe nứt"],"chuSoHuu":[{"ten":"Y Nguyệt","tuChuong":"","denChuong":"@c1228","cachCoDuoc":"Sở hữu ban đầu","trangThai":"da-cho"},{"ten":"Vương Lâm","tuChuong":"@c1228","denChuong":"","cachCoDuoc":"Y Nguyệt trao","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1228","loai":"doi-chu","importance":"major","giaiDoan":"Y Nguyệt trao cho Vương Lâm","text":"Y Nguyệt trao ngọc bội truyền tống cho Vương Lâm như phần thỏa thuận liên minh, Vương Lâm kiểm tra an toàn rồi dùng để rời khe nứt.","anchor":"Cầm lấy ngọc bội này, nó có thể từ bất kỳ nơi đâu vào trong khe nứt"}]},"nguon":["@c1228"]},{"id":"toa-lau-cac-bach-ngoc","name":"Tòa lầu các bạch ngọc","cn":"","category":"khac","categoryLabel":"Vật thể bí ẩn trong thiên kiếp","phamCap":"Không rõ","soHuu":[],"trangThai":"Đang hiện ra từ lỗ hổng vô lượng kiếp","blurb":"Tòa lầu các bằng bạch ngọc xuất hiện từ lỗ hổng trong tầng mây vô lượng kiếp, trên lầu có pho tượng ngồi khoanh chân và hai thanh thạch kiếm.","detail":"Xuất hiện bên trong lỗ hổng mở ra từ tầng mây vô lượng kiếp, đang tiến lại gần. Làm bằng bạch ngọc, thông tới thế giới khác. Đã lộ ra một nửa khi chương kết thúc. Trên lầu có pho tượng ngồi khoanh chân, trước pho tượng cắm hai thanh thạch kiếm.","hinhDang":"Lầu các bằng bạch ngọc","nguonGoc":"Xuất hiện từ thế giới khác qua lỗ hổng trong tầng mây vô lượng kiếp","congNang":["Chưa rõ — đang tiến lại gần qua lỗ hổng thiên kiếp @c1229"],"tabs":{"tienTrinh":[{"chuong":"@c1229","loai":"xuất hiện","importance":"major","giaiDoan":"Hiện ra từ tầng mây vô lượng kiếp","text":"Tòa lầu các bạch ngọc xuất hiện từ lỗ hổng trong tầng mây thiên kiếp, đang tiến lại gần. Trên lầu có pho tượng ngồi khoanh chân, trước người cắm hai thanh thạch kiếm.","anchor":"Tòa lầu các này làm bằng bạch ngọc, đang không ngừng tiến lại gần lỗ hổng"}]},"capNhatToi":"@c1229","nguon":["@c1229"]},{"id":"hai-thanh-thach-kiem","name":"Hai thanh thạch kiếm","cn":"","category":"phap-bao","categoryLabel":"Kiếm / Pháp khí","phamCap":"Không rõ","soHuu":[],"trangThai":"Cắm trước pho tượng trên lầu các","blurb":"Hai thanh kiếm bằng đá cắm trước pho tượng trên lầu các bạch ngọc trong vô lượng kiếp. Lai lịch và công năng chưa rõ.","detail":"Xuất hiện cùng tòa lầu các bạch ngọc và pho tượng bí ẩn trong vô lượng kiếp. Bằng đá, cắm trước người pho tượng ngồi khoanh chân.","hinhDang":"Kiếm bằng đá","nguonGoc":"Chưa rõ, xuất hiện cùng lầu các bạch ngọc trong vô lượng kiếp","tabs":{"tienTrinh":[{"chuong":"@c1229","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện cùng pho tượng trong vô lượng kiếp","text":"Cắm trước pho tượng ngồi khoanh chân trên lầu các bạch ngọc trong tầng mây vô lượng kiếp.","anchor":"Trước người pho tượng này cắm hai thanh thạch kiếm!"}]},"capNhatToi":"@c1229","nguon":["@c1229"]},{"id":"pho-tuong-lau-cac-bach-ngoc","name":"Pho tượng trên lầu các bạch ngọc","cn":"","category":"khac","categoryLabel":"Thực thể bí ẩn","phamCap":"Không rõ","soHuu":[],"trangThai":"Ngồi khoanh chân trên lầu các","blurb":"Pho tượng bí ẩn ngồi khoanh chân trên tòa lầu các bạch ngọc trong vô lượng kiếp, trước người cắm hai thanh thạch kiếm.","detail":"Xuất hiện cùng tòa lầu các bạch ngọc từ lỗ hổng trong tầng mây vô lượng kiếp. Ngồi khoanh chân, hai thanh thạch kiếm cắm trước người. Danh tính chưa rõ.","hinhDang":"Pho tượng ngồi khoanh chân","nguonGoc":"Chưa rõ, xuất hiện từ thế giới khác qua lỗ hổng vô lượng kiếp","tabs":{"tienTrinh":[{"chuong":"@c1229","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện trên lầu các bạch ngọc","text":"Pho tượng ngồi khoanh chân trên lầu các bạch ngọc hiện ra từ tầng mây vô lượng kiếp, trước người cắm hai thanh thạch kiếm.","anchor":"Hắn thấy trên lầu các có một pho tượng đang ngồi khoanh chân"}]},"capNhatToi":"@c1229","nguon":["@c1229"]},{"id":"that-thai-dinh","name":"Thất Thải Đinh","cn":"七彩钉","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Thủy Đạo Tử"],"trangThai":"dang-co","blurb":"Chiếc đinh bảy màu cắm ở mi tâm Thủy Đạo Tử, hắn đang cố ép nó ra nhưng thất bại do ý chí Vương Lâm theo lôi đình kích hoạt nó tỏa sáng.","detail":"Thất Thải Đinh đã lộ ra ngoài mi tâm Thủy Đạo Tử. Hắn đang trong thời khắc mấu chốt ép nó ra khỏi mi tâm thì ý chí Vương Lâm ẩn trong lôi đình thiên kiếp xâm nhập mật thất, kích hoạt Thất Thải Đinh tỏa sáng chói mắt, khiến Thủy Đạo Tử phun máu, toàn bộ công sức uổng phí. Pháp bảo này phản ứng với ý chí/lôi đình Vương Lâm dù chủ nhân đang cố gỡ.","congNang":["Phản ứng với ý chí/lôi đình của Vương Lâm dù đang bị chủ nhân ép gỡ"],"chuSoHuu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1230","denChuong":"","cachCoDuoc":"Cắm ở mi tâm (chưa rõ nguồn gốc)","trangThai":"đang cố ép ra nhưng thất bại"}],"tabs":{"tienTrinh":[{"chuong":"@c1230","loai":"khai phong","importance":"major","giaiDoan":"Bị kích hoạt bởi ý chí Vương Lâm, phá hoại tiến trình ép gỡ của Thủy Đạo Tử","text":"Đã lộ ra ngoài mi tâm Thủy Đạo Tử, hắn đang cố ép ra thì ý chí Vương Lâm theo lôi đình kích hoạt Thất Thải Đinh tỏa sáng chói mắt, khiến Thủy Đạo Tử phun máu, toàn bộ công sức uổng phí.","anchor":"Thất Thải Đinh lúc này đã lộ ra ngoài mi tâm hắn"}]},"nguon":["@c1230"]},{"id":"bon-thanh-kiem-thien-kiep","name":"Bốn thanh kiếm thiên kiếp","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo / Hiện tượng thiên kiếp","phamCap":"Thiên kiếp","soHuu":[],"trangThai":"tiêu tán vào tầng mây ngưng tụ núi mây","blurb":"Bốn trường kiếm (xanh, lam, đen, vàng) ẩn trong bốn thạch kiếm trước pho tượng trên lầu các bạch ngọc, lần lượt vỡ ra trong thiên kiếp, tạo dòng xoáy chứa thế giới mê hoặc rồi ngưng tụ thành núi mây tím chữ đạo.","detail":"Bốn thạch kiếm phía sau pho tượng trên lầu các bạch ngọc lần lượt vỡ ra lộ bốn trường kiếm: xanh (ra trước), lam, đen, vàng. Bốn kiếm vờn quanh trên không xoay tròn tạo dòng xoáy chứa thế giới hỗn độn có tinh cầu và con người, phát tiếng gọi mê hoặc hứa trường sinh thoát luân hồi, hút mất hàng trăm tu sĩ. Dòng xoáy sau đó tiêu tán vào tầng mây, ngưng tụ thành núi mây khổng lồ toàn mây tím với phù văn chữ đạo, uy áp chấn kinh thiên địa đè xuống Vương Lâm.","congNang":["Tạo dòng xoáy mê hoặc hút sinh linh vào vùng đất ước mơ","Biến thành núi mây tím nghiền nát mục tiêu"],"dacDiem":"Ẩn trong thạch kiếm trước pho tượng, phù văn chữ đạo trên núi mây","capNhatToi":"@c1231","tabs":{"tienTrinh":[{"chuong":"@c1231","loai":"xuất hiện","importance":"major","giaiDoan":"Bốn kiếm thiên kiếp lộ diện tạo dòng xoáy mê hoặc","text":"Bốn thạch kiếm lần lượt vỡ ra lộ trường kiếm xanh, lam, đen, vàng, vây công huyết kiếm rồi xoay tạo dòng xoáy chứa thế giới hỗn độn. Tiếng gọi mê hoặc hút hàng trăm tu sĩ biến mất. Dòng xoáy tiêu tán ngưng tụ thành núi mây tím chữ đạo đè xuống Vương Lâm.","anchor":"Bốn thanh kiếm xanh, lam, đen, vàng vờn quanh trên không trung, lập tức xoay tròn"}]},"nguon":["@c1231"]},{"id":"chin-thien-thach-cuu-cung","name":"Chín thiên thạch Cửu Cung","category":"khac","categoryLabel":"Vật của Thiên Kiếp","phamCap":"Thiên Kiếp cấp","soHuu":[],"trangThai":"dang-hoat-dong","blurb":"Chín thiên thạch khổng lồ trong tinh không đã bị luyện hóa từ vô số năm trước thành vật của Thiên Kiếp, thu nhỏ thành chín tinh cầu nhập vào thân Vương Lâm qua chín đốm máu.","detail":"Chín thiên thạch bố trí theo Cửu Cung (càn, khảm, cấn, chấn, trung, tốn, ly, bạng, đoài), không phải tu chân tinh, không có sinh linh. Khi được pho tượng phát động, thu nhỏ xuyên qua lối vào Phong Giới đại trận lao thẳng đến Vương Lâm, nhập thể qua chín đốm máu trắng.","tabs":{"tienTrinh":[{"chuong":"@c1232","loai":"xuất hiện","importance":"normal","giaiDoan":"Nhập thể Vương Lâm","text":"Chín tinh cầu thu nhỏ xuyên qua lối vào Phong Giới đại trận lao đến Vương Lâm, nhập thể qua chín đốm máu cố ngưng tụ ở ngực.","anchor":"Cửu Cung hóa thành tinh cầu kia cũng không phải là tu chân tinh, trên đó cũng không có bất kỳ một sinh linh nào, mà là chín thiên thạch khổng lồ ở bên trong tinh không"}]},"nguon":["@c1232"]},{"id":"ngoc-boi-tong-chu","name":"Ngọc bội Tông Chủ","cn":"宗主玉佩","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (cực phẩm)","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Ngọc bội của chủ nhân Phong Giới (Tông Chủ), ẩn bên trong Thiên Nghịch Châu. Khi kích hoạt, biến ảo ra cây đại thụ chọc trời hiện mặt người Tông Chủ, có thể triệu hoán hình ảnh và phá giải Phong Giới Đại Trận.","detail":"Từ bên trong Thiên Nghịch Châu biến ảo hiện ra khi Vương Lâm truyền thần niệm, xuyên qua thân thể bay ra. Khiến trời đất ầm vang, hư vô run lên, ngay cả Bát Quái Thiên Kiếp cũng chấn động. Được Huyền Bỉnh nhận ra là ngọc bội của Tông Chủ. Khi lóe sáng, biến ảo ra cây đại thụ chọc trời hiện mặt người già nua của Tông Chủ. Sau khi Tông Chủ nói xong, ngọc bội hóa tinh quang rơi xuống Phong Giới Đại Trận, hóa vô số sợi tơ xanh lan tràn phá giải đại trận.","congNang":["Triệu hoán hình ảnh chủ nhân Phong Giới","Phá giải Phong Giới Đại Trận bằng cách hóa sợi tơ xanh thẩm thấu"],"chuSoHuu":[{"ten":"Chủ nhân Phong Giới","tuChuong":"","denChuong":"","cachCoDuoc":"Ngọc bội bản thân","trangThai":"truyen-lai"},{"ten":"Vương Lâm","tuChuong":"@c1233","denChuong":"@c1233","cachCoDuoc":"Ẩn trong Thiên Nghịch Châu, kích hoạt bằng thần niệm","trangThai":"da-dung"}],"nguon":["@c1233"],"tabs":{"tienTrinh":[{"chuong":"@c1233","loai":"xuat-hien","importance":"major","giaiDoan":"Kích hoạt và phá giải Phong Giới Đại Trận","text":"Từ Thiên Nghịch Châu biến ảo hiện ra, triệu hoán hình ảnh Tông Chủ qua cây đại thụ chọc trời. Sau đó hóa tinh quang rơi xuống Phong Giới Đại Trận, phá giải hoàn toàn.","anchor":"Ngọc bội của Tông Chủ! Hắn, hắn không ngờ lại có được ngọc bội của Tông Chủ!","phamCap":"Cực phẩm"}]}},{"id":"tam-khien-mat-quy","name":"Tấm khiên hình mặt quỷ","category":"phap-bao","categoryLabel":"Pháp bảo","soHuu":["Lão giả Toái Niết đại viên mãn (thủ trận giới ngoại)"],"trangThai":"bi-huy","blurb":"Pháp bảo phòng ngự của lão giả Toái Niết đại viên mãn giới ngoại, lấy ra từ ngực. Bị tia chớp đỏ của Vương Lâm xuyên thủng, phát tiếng kêu thê lương rồi nổ tung thành nhiều mảnh.","detail":"Tấm khiên hình mặt quỷ dùng để chống đỡ tấn công. Khi bị tia chớp đỏ đánh trúng, phát ra tiếng kêu thê lương rồi sụp đổ nổ tung.","nguon":["@c1236"],"congNang":["Phòng ngự chống đỡ đòn tấn công"],"chuSoHuu":[{"ten":"Lão giả Toái Niết đại viên mãn (thủ trận giới ngoại)","tuChuong":"@c1236","denChuong":"@c1236","cachCoDuoc":"","trangThai":"bi-huy"}],"tabs":{"tienTrinh":[{"chuong":"@c1236","loai":"dùng","importance":"normal","giaiDoan":"Bị phá hủy khi chống Vương Lâm","text":"Lão giả lấy khiên mặt quỷ từ ngực ra chống đỡ, bị tia chớp đỏ xuyên thủng, phát tiếng kêu thê lương rồi nổ tung thành nhiều mảnh.","anchor":"chiếc khiên mặt quỷ phát ra tiếng kêu thê lương, lập tức sụp đổ"}]}},{"id":"dam-khi-tinh-hon","name":"Đám khí tinh hồn","cn":"","category":"khac","categoryLabel":"Khác (năng lượng)","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Bảy đám khí tinh hồn Vương Lâm rút từ nhiều tu chân tinh, dùng hồi phục nguyên thần.","detail":"Vương Lâm dùng Trừu Tinh Hồn Lực rút tinh hồn từ nhiều tu chân tinh ngoại giới, tạo thành bảy đám khí tinh hồn lơ lửng quanh thân. Mỗi đám to bằng nắm tay, ẩn chứa tinh không, dùng để hồi phục nguyên thần bị thương.","nguon":["@c1238"],"congNang":["Hồi phục nguyên thần bị thương @c1238"],"tabs":{"tienTrinh":[{"chuong":"@c1238","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm rút tinh hồn tạo thành bảy đám khí","text":"Vương Lâm rút tinh hồn từ nhiều tu chân tinh tạo thành bảy đám khí tinh hồn lơ lửng quanh thân, nguyên thần hồi phục gần hết.","anchor":"dần dần bên ngoài thân thể Vương Lâm đã có bảy đám khí tinh hồn lơ lững"}]}},{"id":"van-than-diet-phien","name":"Vân Thần Diệt Phiến","cn":"云神灭扇","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Quạt nguyệt sắc trăm trượng của Nguyệt Tộc, tạo gió lốc trong Phong Thần Đại Trận.","detail":"Một trong các chí bảo Nguyệt Tộc triệu ra trong Phong Thần Đại Trận nhằm phong ấn Cổ Thần. Hình dạng quạt nguyệt sắc lớn trăm trượng, phát gió lốc mãnh liệt. Bị Cổ Thần Bát Tinh thuật Hư quét sạch cùng các pháp bảo khác.","nguon":["@c1239"]},{"id":"huyet-nguyet-thu","name":"Huyết Nguyệt Thú","cn":"血月兽","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Mãnh thú huyết tế của Nguyệt Tộc, tạo ấn ký huyết sắc trong Phong Thần Đại Trận.","detail":"Chí bảo Nguyệt Tộc dùng trong Phong Thần Đại Trận. Huyết tế mãnh thú tạo ra ấn ký huyết sắc tấn công Cổ Thần. Bị Cổ Thần Bát Tinh thuật Hư quét sạch.","nguon":["@c1239"]},{"id":"co-than-cuu-cot","name":"Cổ Thần Cửu Cốt","cn":"古神九骨","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Chín đầu lâu Cổ Thần, nổ tung tương đương chín tu sĩ bước thứ ba tự bạo.","detail":"Chín đầu lâu Cổ Thần được Nguyệt Tộc triệu ra trong Phong Thần Đại Trận. Khi kích hoạt, nổ tung với uy lực tương đương chín tu sĩ bước thứ ba tự bạo, nhằm phá hủy thân thể Cổ Thần. Bị Cổ Thần Bát Tinh thuật Hư quét sạch.","nguon":["@c1239"]},{"id":"hoi-than-dich","name":"Hội Thần Dịch","cn":"会神液","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Biển máu đen hôi thối chuyên luyện hóa Cổ Thần lực.","detail":"Chí bảo Nguyệt Tộc dùng trong Phong Thần Đại Trận, biến thành biển máu đen hôi thối có công năng luyện hóa Cổ Thần lực. Bị Cổ Thần Bát Tinh thuật Hư cuốn đi tiêu tan.","nguon":["@c1239"]},{"id":"mat-cua-co-than","name":"Mắt của Cổ Thần","cn":"古神之眼","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Mắt Cổ Thần do Nguyệt Tộc sở hữu, dùng trong Phong Thần Đại Trận.","detail":"Một trong các chí bảo Nguyệt Tộc triệu ra trong Phong Thần Đại Trận để phong ấn và tấn công Cổ Thần. Bị Cổ Thần Bát Tinh thuật Hư đánh nổ tung.","nguon":["@c1239"]},{"id":"cu-linh-chung","name":"Cự Linh Chung","cn":"巨灵钟","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Chuông cổ phát sóng âm trong Phong Thần Đại Trận.","detail":"Chuông cổ Nguyệt Tộc triệu ra trong Phong Thần Đại Trận, phát sóng âm nhắm vào Cổ Thần. Sóng chuông bị Cổ Thần Bát Tinh thuật Hư quét tiêu tán.","nguon":["@c1239"]},{"id":"diet-the-de-cuu-linh","name":"Diệt Thế Đệ Cửu Linh","cn":"灭世第九灵","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Chí bảo Nguyệt Tộc","soHuu":["Nguyệt Tộc"],"trangThai":"Bị phá hủy","blurb":"Hư ảnh xanh có khí tức giống đầu lâu Cổ Thần vùng đất Yêu Linh.","detail":"Chí bảo Nguyệt Tộc triệu ra cuối cùng trong chuỗi pháp bảo Phong Thần Đại Trận. Là hư ảnh xanh mang khí tức tương tự đầu lâu Cổ Thần ở vùng đất Yêu Linh. Bị Cổ Thần Bát Tinh thuật Hư quét tan thành mây khói.","nguon":["@c1239"]},{"id":"tan-cot-co-than-nguyet-toc","name":"Tàn cốt Cổ Thần (chí bảo Nguyệt Tộc)","cn":"古神残骨","aliases":["Đốt xương ngón tay Cổ Thần gần cửu tinh","Cổ Thần tàn cốt"],"category":"than-khi","categoryLabel":"Thần khí","phamCap":"Gần cửu tinh Cổ Thần","soHuu":["Nguyệt Tộc","Vương Lâm","Thác Sâm"],"trangThai":"Bị chẻ đôi — nửa thuộc Vương Lâm, nửa thuộc Thác Sâm","blurb":"Đốt xương ngón tay Cổ Thần gần cửu tinh, đệ nhất bảo vật hộ tộc tối thượng của Nguyệt Tộc.","detail":"Đốt xương ngón tay của Cổ Thần gần cửu tinh (không phải thực sự cửu tinh), là bảo vật hộ tộc tối thượng của Nguyệt Tộc, được chuẩn bị vô số vạn năm. Lão giả tóc bạc Nguyệt Tộc tuyệt vọng triệu ra để đánh hai Cổ Thần. Đốt xương hạ xuống đánh vỡ ký hiệu Bát Tinh thuật Hư, khiến Thác Sâm phun máu ném xa, Vương Lâm xương cốt vỡ vụn toàn thân. Lần thứ hai được triệu sau hiến tế Nguyệt linh, đâm vào Thác Sâm. Thác Sâm cố thôn phệ nhưng Vương Lâm dùng huyết kiếm chém nứt đốt xương làm đôi. Một nửa bị Thác Sâm hút vào tinh điểm, nửa còn lại bị Vương Lâm đoạt mang đi.","nguon":["@c1239"]},{"id":"luc-pham-dao-linh","name":"Lục phẩm đạo linh","cn":"六品道灵","aliases":[],"category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Lục phẩm","soHuu":["Lão già Không Linh (Viễn Cổ Tinh Thần)","Ti Mặc Tử"],"trangThai":"Đã trao","blurb":"Đạo linh lục phẩm, phần thưởng nữ tử áo trắng trao cho hai cao thủ Viễn Cổ Tinh Thần.","detail":"Nữ tử áo trắng mang khí tức Tiên Vực trao cho lão già Không Linh và Ti Mặc Tử mỗi người một viên lục phẩm đạo linh như đã hứa trước, sau khi hai người hoàn thành việc truy sát (hoặc phối hợp theo dõi) Thác Sâm.","nguon":["@c1239"]},{"id":"nua-dot-xuong-ngon-tay-co-than","name":"Nửa đốt xương ngón tay Cổ Thần","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","soHuu":["Vương Lâm"],"trangThai":"đang sở hữu","blurb":"Nửa đốt xương ngón tay của Cổ Thần, chiến lợi phẩm Vương Lâm thu được sau trận chiến với Thác Sâm, chưa kịp nghiên cứu.","detail":"Được Vương Lâm thu vào khe trữ vật sau khi thoát khỏi cuộc đuổi giết của Thác Sâm. Chưa rõ công dụng cụ thể, chưa kịp nghiên cứu chi tiết.","tabs":{"tienTrinh":[{"chuong":"@c1240","loai":"xuất hiện","importance":"normal","giaiDoan":"Thu hoạch","text":"Vương Lâm thu nửa đốt xương ngón tay Cổ Thần vào khe trữ vật sau trận chiến với Thác Sâm.","anchor":"Nửa đốt xương ngón tay của Cổ Thần đã được Vương Lâm đưa vào trong khe trữ vật"}]},"nguon":["@c1240"]},{"id":"nam-dao-khi-thien-thach","name":"Năm đạo khí thiên thạch thiên ngoại","cn":"","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Cực phẩm (khiến chưởng tôn kiêng dè)","soHuu":["Lam Mộng Đạo Tôn"],"trangThai":"dang-co","blurb":"Năm đạo khí do Lam Mộng Đạo Tôn luyện hóa từ năm thiên thạch thiên ngoại, xuất ra trời long đất lở, khiến chưởng tôn cũng kiêng dè.","detail":"Lam Mộng Đạo Tôn luyện hóa từ năm thiên thạch thiên ngoại thành năm đạo khí. Uy lực cực lớn, xuất ra trời long đất lở. Ngay cả chưởng tôn cũng phải cố kỵ. Đề nghị trao cho Vương Lâm nhưng bị từ chối vì đi kèm điều kiện thoát ly giới nội.","congNang":["Xuất ra trời long đất lở, uy lực khiến chưởng tôn kiêng dè"],"chuSoHuu":[{"ten":"Lam Mộng Đạo Tôn","tuChuong":"@c1243","denChuong":"","cachCoDuoc":"Tự luyện hóa từ thiên thạch thiên ngoại","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1243","loai":"xuat-hien","importance":"normal","giaiDoan":"Được Lam Mộng nhắc tới khi chiêu mộ Vương Lâm","text":"Lam Mộng Đạo Tôn đề cập năm đạo khí luyện từ thiên thạch thiên ngoại, xuất ra trời long đất lở, chưởng tôn cũng kiêng dè. Đề nghị trao cho Vương Lâm nhưng bị từ chối.","anchor":"Năm đạo khí đó xuất ra là trời long đất lở"}]},"nguon":["@c1243"]},{"id":"vong-tam-qua","name":"Vong tâm quả","cn":"忘心果","category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":"Không rõ","soHuu":["Lam Mộng Đạo Tôn"],"trangThai":"dang-co","blurb":"Vật phẩm dùng kèm lời thề bổn nguyên để thoát ly giới nội, ngụ ý giúp quên đi gốc rễ và ràng buộc cũ.","detail":"Điều kiện thứ nhất của Lam Mộng Đạo Tôn yêu cầu Vương Lâm ăn vong tâm quả, phát lời thề bổn nguyên thoát ly giới nội, trở thành người Thái Cổ Tinh Thần. Vương Lâm cự tuyệt.","congNang":["Dùng kèm thề bổn nguyên để thoát ly giới nội, quên gốc rễ cũ"],"chuSoHuu":[{"ten":"Lam Mộng Đạo Tôn","tuChuong":"@c1243","denChuong":"","cachCoDuoc":"Sẵn có","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1243","loai":"xuat-hien","importance":"normal","giaiDoan":"Được nhắc tới trong điều kiện chiêu mộ Vương Lâm","text":"Lam Mộng yêu cầu Vương Lâm ăn vong tâm quả và phát lời thề bổn nguyên thoát ly giới nội. Bị Vương Lâm cự tuyệt.","anchor":"Ngươi phải ăn vong tâm quả, phát lời thề bổn nguyên, thoát ly giới nội"}]},"nguon":["@c1243"]},{"id":"tieu-cau-loc-xoay-lam-mong","name":"Tiểu cầu lốc xoáy (Lam Mộng Đạo Tôn)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã tiêu tan","blurb":"Vật phẩm chứa đạo thuật dung hợp do Lam Mộng Đạo Tôn truyền thụ, Vương Lâm dùng năm đạo bổn nguyên hấp thu hết khí bên trong, tiểu cầu hoàn toàn tiêu tan.","detail":"Tiểu cầu lốc xoáy trôi nổi giữa không trung cùng thanh kiếm băng từ khi Lam Mộng Đạo Tôn rời đi. Chứa đạo thuật dung hợp bên trong. Vương Lâm dùng hai ngón tay kẹp, năm đạo bổn nguyên xoay trong đồng tử hấp thu khí vô hình từ tiểu cầu. Mấy ngày sau tiểu cầu hoàn toàn tiêu tan.","congNang":["Truyền thụ đạo thuật dung hợp khi được hấp thu bởi bổn nguyên"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1245","denChuong":"@c1245","cachCoDuoc":"Lam Mộng Đạo Tôn truyền thụ","trangThai":"đã tiêu tan"}],"capNhatToi":"@c1245","tabs":{"tienTrinh":[{"chuong":"@c1245","loai":"dùng","importance":"major","giaiDoan":"Vương Lâm hấp thu hoàn toàn, tiểu cầu tiêu tan","text":"Vương Lâm dùng năm đạo bổn nguyên hấp thu khí từ tiểu cầu lốc xoáy, mấy ngày sau tiểu cầu hoàn toàn tiêu tan, hoàn tất truyền thụ đạo thuật dung hợp.","anchor":"tiểu cầu lốc xoáy này hoàn toàn tiêu tan"}]},"nguon":["@c1245"]},{"id":"thanh-kiem-bang-lam-mong","name":"Thanh kiếm băng (Lam Mộng Đạo Tôn)","cn":"","category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đã biến đổi/tiêu hủy","blurb":"Thanh kiếm băng trôi nổi giữa không trung từ khi Lam Mộng Đạo Tôn rời đi, bị Vương Lâm dùng đạo thuật dung hợp biến thành mảnh băng, nước mưa, sương mù rồi đám mây trắng bay đi.","detail":"Thanh kiếm băng trôi nổi giữa không trung cùng tiểu cầu lốc xoáy, tuyết không bám được lên bề mặt. Vương Lâm dùng đạo thuật dung hợp lần đầu trên thanh kiếm này: kiếm nứt vỡ thành mảnh băng, mảnh băng hòa tan thành nước mưa, nước mưa thành lốc xoáy sương mù, sương mù hóa thành đám mây trắng bay đi. Đây là biểu hiện đầu tiên của khả năng dung hợp/biến đổi vật chất.","congNang":[],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1245","denChuong":"@c1245","cachCoDuoc":"Lam Mộng Đạo Tôn để lại","trangThai":"đã biến đổi/tiêu hủy"}],"capNhatToi":"@c1245","tabs":{"tienTrinh":[{"chuong":"@c1245","loai":"dùng","importance":"normal","giaiDoan":"Bị Vương Lâm dùng đạo thuật dung hợp biến thành mây trắng","text":"Vương Lâm cầm thanh kiếm băng, dùng đạo thuật dung hợp biến kiếm thành mảnh băng, nước mưa, sương mù rồi đám mây trắng bay đi — biểu hiện đầu tiên của đạo thuật dung hợp.","anchor":"từ bên trong tinh thể băng kia truyền ra âm thanh tách tách, trên đó bất chợt có rất nhiều vết nứt xuất hiện"}]},"nguon":["@c1245"]},{"id":"nua-dot-ngon-tay-co-than","name":"Nửa đốt ngón tay Cổ Thần","cn":"","category":"phap-bao","categoryLabel":"Bảo vật","phamCap":"Chí bảo cấp Cổ Thần","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Nửa đốt ngón tay chứa khí tức Cổ Thần nồng đậm thực chất hóa, kích cỡ so được với tu chân tinh. Bên trong có ý chí tồn tại chống lại mọi sự cắn nuốt hấp thụ.","detail":"Vương Lâm lấy từ khe trữ vật, kích cỡ sánh ngang tu chân tinh. Khí tức Cổ Thần bên trong nồng đậm đến mức thực chất hóa. Chứa ý chí tồn tại không cho cắn nuốt. Vương Lâm dùng tinh điểm Cổ Thần trên mi tâm thử hấp thụ nhưng thất bại. Thác Sâm trước đó cũng muốn dùng tinh điểm nuốt nhưng gặp khó vì ý chí bên trong.","congNang":["Chứa khí tức Cổ Thần nồng đậm thực chất hóa"],"dacDiem":"Ý chí tồn tại bên trong chống cắn nuốt, kích cỡ sánh ngang tu chân tinh","tabs":{"tienTrinh":[{"chuong":"@c1247","loai":"xuất hiện","importance":"normal","giaiDoan":"Vương Lâm thử hấp thụ — thất bại","text":"Vương Lâm lấy nửa đốt ngón tay ra, dùng tinh điểm Cổ Thần trên mi tâm thử hấp thụ nhưng thất bại vì ý chí bên trong chống lại.","anchor":"đốt ngón tay rất lớn từ bên trong cái khe chậm rãi bay ra, trôi giữa không trung, nhìn giống như một khối đại lục"}]},"nguon":["@c1247"]},{"id":"linh-chung","name":"Linh Chủng","cn":"灵种","category":"khac","categoryLabel":"Vật phẩm đặc thù","phamCap":"Không rõ","soHuu":["Nguyệt Phệ Tộc"],"trangThai":"dang-co","blurb":"Vật thể ký sinh trong cơ thể Nguyệt Phệ Tộc, là điều kiện bắt buộc để tu luyện Thanh Vân Linh Thuật hấp thụ sức mạnh Cổ Thần.","detail":"Linh Chủng do đám người thần bí để lại cho Nguyệt Tộc khi trợ giúp họ nổi loạn chống Cổ Thần. Ký sinh trong cơ thể người Nguyệt Tộc, được trồng ngày càng nhiều qua các thế hệ. Là điều kiện tiên quyết tu luyện Thanh Vân Linh Thuật.","nguon":["@c1248"]},{"id":"ngoc-boi-bach-y-nu-tu","name":"Ngọc bội (Bạch Y Nữ Tử)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Nữ tử áo trắng"],"trangThai":"hu-ton","blurb":"Ngọc bội do phân thân Bạch Y Nữ Tử phun ra, vừa hình thành phòng hộ vừa là vật liên kết bổn tôn, cho phép bổn tôn phóng chiếu cánh tay qua ngọc bội tấn công.","detail":"Bạch Y Nữ Tử phun ngọc bội ra từ miệng, hình thành phòng hộ trắng chống lại Phiên Thiên Ấn và cản trường kiếm đen bị chiết xạ ngược. Bị huyết kiếm Vương Lâm đánh nứt nhưng vẫn hoạt động. Khi phân thân kêu cứu, từ ngọc bội hiện ra cánh tay trắng như ngọc của bổn tôn, ấn ngón tay xuống với uy lực kinh thiên vượt cả Thủy Đạo Tử, xuyên phá Quang Ảnh Thuẫn hoàn toàn.","hinhDang":"Ngọc bội","congNang":["Hình thành phòng hộ trắng bao bọc chủ nhân","Liên kết bổn tôn, cho phép bổn tôn phóng chiếu cánh tay qua ngọc bội tấn công"],"dacDiem":"Bị huyết kiếm đánh nứt nhưng vẫn duy trì chức năng liên kết bổn tôn","chuSoHuu":[{"ten":"Nữ tử áo trắng","tuChuong":"@c1249","denChuong":"","cachCoDuoc":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1249","loai":"dùng","importance":"major","giaiDoan":"Xuất hiện + bị hư tổn + bổn tôn phóng chiếu","phamCap":"","text":"Bạch Y Nữ Tử phun ngọc bội phòng hộ chống Phiên Thiên Ấn, bị huyết kiếm đánh nứt. Phân thân kêu cứu, từ ngọc bội hiện ra cánh tay bổn tôn ấn ngón tay uy lực vượt Thủy Đạo Tử, xuyên phá Quang Ảnh Thuẫn.","anchor":"Một cánh tay trắng như ngọc từ trong ngọc bội hiện ra, hướng về phía Vương Lâm điểm một cái"}]},"nguon":["@c1249"]},{"id":"an-ky-chu-xuyen","name":"Ấn ký hình chữ Xuyên","cn":"穿字印记","aliases":[],"category":"khac","categoryLabel":"Ấn ký","phamCap":"Không rõ","soHuu":["Bạch Y Nữ Tử"],"trangThai":"Đã kích hoạt (trước khi vật chủ tử vong)","blurb":"Ấn ký xuất hiện trên mi tâm Bạch Y Nữ Tử trong lúc nguy cấp, phát ba đạo ánh sáng đỏ, vàng, lam, kích hoạt ký ức bị phong ấn và bùng phát khí tức trắng sữa hỗ trợ phòng ngự/thoát thân.","detail":"Ấn ký có hình chữ “xuyên”, vốn không hiện trên mi tâm trơn nhẵn của Bạch Y Nữ Tử, chỉ lộ ra khi nàng lâm vào tình thế chí nguy. Khi kích hoạt, ấn ký phóng ra ba đạo ánh sáng đỏ, vàng, lam đồng thời khơi dậy ký ức bị phong ấn: nàng từng là thánh nữ bộ tộc, bị một bàn tay trắng nõn xóa tộc ấn gốc rồi thay bằng ấn ký này, biến nàng thành phân thân nuôi dưỡng hình chiếu và cánh cửa hương hỏa. Khí tức trắng sữa bùng lên từ ấn ký đủ sức đối kháng nắm đấm bổn nguyên của Vương Lâm và hỗ trợ na di thoát thân.","nguon":["@c1251"]},{"id":"kim-tuyen-phan-than-lan-phi","name":"Kim tuyến phân thân Lan Phi","cn":"金线","aliases":["Kim tuyến"],"category":"khac","categoryLabel":"Vật ký sinh","phamCap":"Không rõ","soHuu":["Lan Phi"],"trangThai":"Bị Ngân Y Nữ Thi nuốt","blurb":"Phân thân của Lan Phi (Viễn Cổ Bát Phi) ký sinh trong cơ thể Bạch Y Nữ Tử, khi vật chủ chết hóa thành kim tuyến phi vật chất lao vào hư vô, bị Ngân Y Nữ Thi bắt và nuốt.","detail":"Kim tuyến này là phân thân của Lan Phi trong Viễn Cổ Bát Phi, ký sinh bên trong cơ thể Bạch Y Nữ Tử. Khi vật chủ tử vong, kim tuyến thoát ra và lao vào hư vô định quay về bên người Lan Phi để trị thương. Kim tuyến có tính chất phi vật chất — huyết kiếm của Vương Lâm xuyên qua mà không gây bất kỳ thương tổn nào. Tuy nhiên Ngân Y Nữ Thi tùy ý giơ tay túm một cái liền kéo kim tuyến đã biến mất trong hư vô quay trở lại; kim tuyến run rẩy sợ hãi trong tay nàng. Ngân Y Nữ Thi vuốt nhẹ, kim tuyến tan vỡ hóa sương vàng chui vào thất khiếu nàng, nàng nói khí tức kim tuyến rất quen thuộc.","nguon":["@c1251"]},{"id":"thiem-dien-van-nam-bat-diet","name":"Đạo thiểm điện vạn năm bất diệt","cn":"闪电","aliases":["Thánh vật Thiểm Lôi Tộc"],"category":"than-khi","categoryLabel":"Thánh vật","phamCap":"Thánh vật tộc","soHuu":["Thiểm Lôi Tộc"],"trangThai":"Tồn tại trong Thiểm Lôi Tộc, bị Vương Lâm nhắm làm mục tiêu","blurb":"Thánh vật của Thiểm Lôi Tộc, tồn tại từ khai thiên lập địa, vạn vạn năm bất diệt, thủy chung xuyên qua trời đất, là nguồn suối sức mạnh toàn tộc.","detail":"Đạo thiểm điện này vạn vạn năm bất diệt, thủy chung xuyên qua trời đất, là thánh vật của Thiểm Lôi Tộc và cũng là nguồn suối sức mạnh của toàn bộ bộ tộc. Vương Lâm từ trí nhớ của những tu sĩ bị cắn nuốt mà biết được sự tồn tại của nó, nhận định nếu nuốt được đạo thiểm điện này sẽ khiến lôi bổn nguyên tiến thêm một bước lớn. Do Thiểm Lôi Tộc không có tu sĩ Đệ Tam Bộ, Vương Lâm quyết định lấy đây làm mục tiêu tiếp theo.","nguon":["@c1251"]},{"id":"loi-qua","name":"Lôi quả","cn":"雷果","category":"nguyen-lieu","categoryLabel":"Linh quả","phamCap":"Không rõ","soHuu":["Tề Trì"],"trangThai":"con-nguyen","blurb":"Quả từ cây lôi quả, to bằng nắm tay, màu xanh sậm, phát ra sấm sét yếu. Nuốt vào sẽ mở rộng tộc ấn và tăng tuổi thọ cho người Thiểm Lôi Tộc.","detail":"Lôi quả sinh trưởng trên cây lôi quả mọc ở vách đá sơn cốc, thân cây thò ra ngoài bảy thước. Quả to bằng nắm tay, màu xanh sậm, bề mặt phát ra sấm sét yếu ớt. Khi tu sĩ Thiểm Lôi Tộc nuốt lôi quả, tộc ấn trên mi tâm sẽ được mở rộng thêm, đồng thời tuổi thọ cũng tăng lên. Tuy nhiên cây lôi quả cần được tu sĩ tối thiểu cảnh giới Kết Đan tẩm bổ sấm sét để nuôi dưỡng. Vu Phi từng trồng chín cây, vừa nuốt một quả thì bị Tề Trì đánh trọng thương và cướp mất động phủ. Khi Vương Lâm chiếm lại động phủ, trên cây còn sáu quả.","nguon":["@c1253","@c1254"],"tabs":{"tienTrinh":[{"chuong":"@c1254","loai":"xuat-hien","importance":"normal","giaiDoan":"Được Vương Lâm khảo sát","text":"Vương Lâm hái một Lôi quả trong động phủ Tề Trì, bóp vỡ hấp thu sấm sét vào nguyên thần. Nhận định một quả đổi được một khối Lôi Tinh.","anchor":"một Lôi quả có thể đổi lấy một khối Lôi Tinh"}]},"congNang":["Cải thiện thể chất thích hợp thi triển thần thông sấm sét","Hấp thu sấm sét vào nguyên thần (cách dùng của Vương Lâm)"]},{"id":"thiem-loi-bang","name":"Thiểm Lôi Bảng","cn":"闪雷榜","category":"khac","categoryLabel":"Ngọc giản / Bảng xếp hạng","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Lấy từ mi tâm Tề Trì, đang do Vương Lâm nắm giữ","blurb":"Ngọc giản chứa trận pháp liên kết thiên địa, hiển thị danh sách 800 người xếp theo Lôi Tinh, nội dung thay đổi theo thời gian thực.","detail":"Thiểm Lôi Bảng là một ngọc giản đặc biệt ẩn chứa trận pháp có thể vận chuyển bất cứ lúc nào, mơ hồ dung hợp cùng thiên địa. Bảng hiển thị danh sách 800 người trên 13 tu chân tinh của Thiểm Lôi Tộc, xếp hạng theo số Lôi Tinh tích lũy. Cứ mỗi trăm năm, người đứng đầu bảng được vào thánh địa tiếp xúc sấm sét bất diệt. Nội dung bảng thay đổi theo thời gian thực. Người đứng đầu hiện tại là Vân Sam Tử với 19,7 tỷ Lôi Tinh, thứ hai là Phù Dung với 13,9 tỷ, vị trí 800 cũng hơn 40 vạn Lôi Tinh. Còn 7 năm nữa sẽ diễn ra tranh đoạt. Vương Lâm lấy ngọc giản này từ trong ký hiệu mi tâm của Tề Trì sau khi chế phục lão.","nguon":["@c1253"]},{"id":"canh-cay-loi-quang","name":"Cành cây Lôi quang","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đã bị Vương Lâm thu","blurb":"Cành cây to như cánh tay, lóe Lôi quang, Chung Đại Hồng cất giấu kỹ rồi dâng cho Vương Lâm, cùng đan dược tử quang tổng cộng đổi được một vạn Lôi tinh.","detail":"Một trong hai vật phẩm Chung Đại Hồng giấu riêng, dâng cho Vương Lâm khi bị ép giao nộp toàn bộ vật đổi Lôi tinh tại Thiên Lôi Tông.","congNang":["Đổi Lôi tinh (cùng đan dược tử quang tổng một vạn Lôi tinh)"],"chuSoHuu":[{"ten":"Chung Đại Hồng","tuChuong":"@c1255","denChuong":"@c1255","cachCoDuoc":"Sở hữu sẵn","trangThai":"da-giao"},{"ten":"Vương Lâm","tuChuong":"@c1255","denChuong":"","cachCoDuoc":"Chung Đại Hồng dâng nộp","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1255","loai":"đổi chủ","importance":"normal","giaiDoan":"Chung Đại Hồng dâng nộp cho Vương Lâm","text":"Chung Đại Hồng lấy ra cành cây Lôi quang cất giấu kỹ dâng cho Vương Lâm, cùng đan dược tử quang tổng cộng đổi được một vạn Lôi tinh.","anchor":"vật phẩm đầu tiên là một cành cây to như cánh tay và lóe lên Lôi quang"}]},"nguon":["@c1255"]},{"id":"phi-kiem-sac-ben","name":"Phi kiếm sắc bén","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đã bị Vương Lâm thu","blurb":"Thanh phi kiếm cực kỳ sắc bén bùng ra khí tức lạnh lẽo, Chung Đại Hồng dâng cho Vương Lâm, có thể đổi lấy mười vạn Lôi tinh.","detail":"Phi kiếm Chung Đại Hồng giao nộp cho Vương Lâm tại quảng trường Thiên Lôi Tông, giá trị đổi mười vạn Lôi tinh.","congNang":["Phi kiếm chiến đấu, khí tức lạnh lẽo","Đổi được mười vạn Lôi tinh"],"chuSoHuu":[{"ten":"Chung Đại Hồng","tuChuong":"@c1255","denChuong":"@c1255","cachCoDuoc":"Sở hữu sẵn","trangThai":"da-giao"},{"ten":"Vương Lâm","tuChuong":"@c1255","denChuong":"","cachCoDuoc":"Chung Đại Hồng dâng nộp","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1255","loai":"đổi chủ","importance":"normal","giaiDoan":"Chung Đại Hồng dâng nộp cho Vương Lâm","text":"Chung Đại Hồng dâng thanh phi kiếm cực kỳ sắc bén cho Vương Lâm, đổi được mười vạn Lôi tinh.","anchor":"Trong ô quang là một thanh phi kiếm cực kỳ sắc bén, đồng thời còn bùng ra những luồng khí tức cực kỳ lạnh lẽo"}]},"nguon":["@c1255"]},{"id":"ham-hon-dan","name":"Hàm Hồn đan","cn":"","category":"dan-duoc","categoryLabel":"Đan dược","phamCap":"Không rõ","soHuu":["Chung Đại Hồng"],"trangThai":"Đã tặng cho Chung Đại Hồng","blurb":"Đan dược Vương Lâm luyện chế tiện tay bằng thú hồn cấp bốn trên Vân Hải tinh vực, có thể đổi hai vạn Lôi tinh, cực kỳ hiếm.","detail":"Vương Lâm tặng cho Chung Đại Hồng để buộc hắn tận tâm sưu tập vật phẩm của Thiểm Lôi Tộc đổi Lôi tinh, tránh dùng đan dược mình đổi trực tiếp sẽ tăng thực lực cho Thiểm Lôi Tộc.","congNang":["Đổi được hai vạn Lôi tinh, cực kỳ hiếm"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1255","denChuong":"@c1255","cachCoDuoc":"Tự luyện chế bằng thú hồn cấp bốn trên Vân Hải tinh vực","trangThai":"da-giao"},{"ten":"Chung Đại Hồng","tuChuong":"@c1255","denChuong":"","cachCoDuoc":"Vương Lâm ban tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1255","loai":"đổi chủ","importance":"normal","giaiDoan":"Vương Lâm tặng cho Chung Đại Hồng","text":"Vương Lâm lấy ra Hàm Hồn đan luyện chế tiện tay, tặng cho Chung Đại Hồng để buộc hắn sưu tập vật đổi Lôi tinh.","anchor":"Hàm Hồn đan! Đan dược này có thể đổi lấy hai vạn Lôi tinh. hơn nữa lại cực kỳ hiếm có"}]},"nguon":["@c1255"]},{"id":"phi-kiem-ban-chung-dai-hong","name":"Thanh phi kiếm (Vương Lâm ban Chung Đại Hồng)","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tầm thường (đối với Vương Lâm), bảo vật khủng bố (đối với Đệ Nhất Bộ)","soHuu":["Chung Đại Hồng"],"trangThai":"dang-dung","blurb":"Thanh phi kiếm Vương Lâm ban cho Chung Đại Hồng, tầm thường với Vương Lâm nhưng là bảo vật khủng bố đối với tu sĩ Đệ Nhất Bộ, giúp Chung Đại Hồng chiến đấu ngang Hóa Thần trung kỳ.","detail":"Một thanh phi kiếm rất tầm thường đối với Vương Lâm, nhưng đối với tu sĩ Đệ Nhất Bộ thì là bảo vật khủng bố. Vương Lâm ban cho Chung Đại Hồng (tu vi Hóa Thần) để hắn đi thu gom vật phẩm đổi Lôi tinh. Nhờ thanh kiếm này, Chung Đại Hồng có thể chiến đấu ngang Hóa Thần trung kỳ và chống đỡ được Hóa Thần hậu kỳ.","congNang":["Tăng chiến lực Chung Đại Hồng từ Hóa Thần lên ngang Hóa Thần trung kỳ, chống đỡ được Hóa Thần hậu kỳ"],"chuSoHuu":[{"ten":"Chung Đại Hồng","tuChuong":"@c1256","denChuong":"","cachCoDuoc":"Vương Lâm ban cho","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1256","loai":"đổi chủ","importance":"normal","giaiDoan":"Vương Lâm ban cho Chung Đại Hồng","text":"Vương Lâm ban cho Chung Đại Hồng thanh phi kiếm tầm thường, nhờ đó Chung Đại Hồng chiến lực ngang Hóa Thần trung kỳ, chống đỡ được Hóa Thần hậu kỳ.","anchor":"Kiếm này rất tầm thường nhưng đối với tu sĩ Đệ Nhất Bộ thì chính là bảo vật kh*ng b*"}]},"nguon":["@c1256"]},{"id":"loi-tinh","name":"Lôi tinh","cn":"雷晶","aliases":[],"category":"khac","categoryLabel":"Tiền tệ / Vật phẩm giao dịch","phamCap":"Không rõ","soHuu":[],"trangThai":"dang-co","blurb":"Đơn vị giao dịch duy nhất trong Thiểm Lôi Tộc, chỉ có thể đổi tại Lôi Tinh Điện trong ba ngày mở cửa mỗi năm, không thể mang đi hay giao dịch riêng tư.","detail":"Lôi tinh là đơn vị tiền tệ và giao dịch của Thiểm Lôi Tộc. Mỗi năm Lôi Tinh Điện chỉ mở ba ngày để tộc nhân mang vật phẩm đến đổi lấy Lôi tinh. Lôi tinh không thể mang đi, không thể giao dịch riêng tư — chỉ có thể giao dịch qua Lôi Tinh Điện. Tuy nhiên, những lão quái tu vi cao thâm có phương pháp lén lút giao dịch bằng vật phẩm có giá trị Lôi tinh tương ứng, nhưng rất nguy hiểm. Dùng để mua pháp bảo và công pháp của Thiểm Lôi Tộc.","congNang":["Đơn vị tiền tệ duy nhất của Thiểm Lôi Tộc, dùng để đổi pháp bảo và công pháp tại Lôi Tinh Điện"],"dacDiem":"Không thể mang đi, chỉ giao dịch qua Lôi Tinh Điện, mỗi năm chỉ giao dịch được ba ngày","tabs":{"tienTrinh":[{"chuong":"@c1258","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới thiệu hệ thống tiền tệ Thiểm Lôi Tộc","text":"Được giới thiệu là đơn vị giao dịch duy nhất trong Thiểm Lôi Tộc, chỉ có thể đổi tại Lôi Tinh Điện trong ba ngày mở cửa mỗi năm.","anchor":"Lôi tinh không thể nào đem đi, chỉ có thể giao dịch với Lôi Tinh Điện mà thôi"}]},"dinhDanh":"goc","capNhatToi":"@c1258","nguon":["@c1258"]},{"id":"ngoc-gian-thiem-loi-bang","name":"Ngọc giản Thiểm Lôi Bảng","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Tộc nhân Thiểm Lôi Tộc"],"trangThai":"dang-dung","blurb":"Ngọc giản của tộc nhân Thiểm Lôi Tộc, tự động hiển thị bảng xếp hạng Lôi tinh, bùng sóng gợn khi bảng thay đổi.","detail":"Mỗi tộc nhân Thiểm Lôi Tộc trên tất cả tu chân tinh đều sở hữu một khối ngọc giản Thiểm Lôi Bảng. Khi bảng xếp hạng thay đổi, ngọc giản lập tức bùng ra những con sóng gợn báo hiệu. Hiển thị tám trăm vị trí cùng số lượng Lôi tinh tương ứng.","congNang":["Tự động hiển thị thứ hạng Lôi tinh toàn tộc trên các tu chân tinh","Bùng sóng gợn khi có biến động bảng xếp hạng"],"tabs":{"tienTrinh":[{"chuong":"@c1259","loai":"xuất hiện","importance":"normal","giaiDoan":"Bảng biến động khi Vu Phi lọt vào","text":"Ngọc giản Thiểm Lôi Bảng trên tất cả tu chân tinh đồng loạt bùng sóng gợn báo hiệu bảng xếp hạng thay đổi, tên Vu Phi xuất hiện ở vị trí 799.","anchor":"Đúng lúc này tất cả ngọc giản Thiểm Lôi Bảng của tộc nhân Thiểm Lôi Tộc trên tất cả tu chân tinh lập tức bùng ra những con sóng gợn"}]},"capNhatToi":"@c1259","nguon":["@c1259"]},{"id":"ngoc-gian-menh-hon-vu-phi","name":"Ngọc giản mệnh hồn Vu Phi","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-dung","blurb":"Ngọc giản có chứa mệnh hồn của Vu Phi, dùng để ghi chép Lôi tinh khi đổi vật phẩm tại ao đen cửa đông Lôi Tinh Điện.","detail":"Vốn là vật của Vu Phi, trên đó có mệnh hồn. Vương Lâm chiếm dụng, dùng nó ném vào ao đen để đổi lượng lớn vật phẩm lấy Lôi tinh. Sau khi ao nuốt vật phẩm, trả lại ngọc giản đã ghi chép số lượng Lôi tinh đổi được.","congNang":["Ghi chép lượng Lôi tinh đổi được tại ao đen cửa đông Lôi Tinh Điện"],"chuSoHuu":[{"ten":"Vu Phi","tuChuong":"@c1252","denChuong":"@c1252","cachCoDuoc":"Vật gốc","trangThai":"da-mat"},{"ten":"Vương Lâm","tuChuong":"@c1252","denChuong":"","cachCoDuoc":"Chiếm dụng sau khi giết Vu Phi","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1259","loai":"dùng","importance":"normal","giaiDoan":"Dùng đổi Lôi tinh tại cửa đông","text":"Vương Lâm ném ngọc giản mệnh hồn Vu Phi vào ao đen cửa đông Lôi Tinh Điện, đổi lượng lớn vật phẩm lấy Lôi tinh, chính thức lên Thiểm Lôi Bảng dưới tên Vu Phi.","anchor":"hắn khẽ lật tay phải và lấy ra một khối ngọc giản, thứ này là vật của Vu Phi, trên đó có mệnh hồn, là vật để ghi chép Lôi tinh"}]},"capNhatToi":"@c1259","nguon":["@c1259"]},{"id":"tu-loi-hoan","name":"Tụ Lôi Hoàn","cn":"聚雷丸","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Lôi cầu như ngón tay cái do lão già Dương Thực cửa đông Lôi Tinh Điện tự luyện hóa, nén 8900 lần, tặng Vương Lâm phòng thân.","detail":"Tụ Lôi Hoàn hình dạng như lôi cầu cỡ ngón tay cái, do một trong ba lão già Dương Thực phụ trách cửa đông Lôi Tinh Điện tự tay luyện hóa. Đã được nén lại tám ngàn chín trăm lần, tặng cho người mới lên Thiểm Lôi Bảng để phòng thân.","congNang":["Phòng thân, lôi cầu nén 8900 lần"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1260","denChuong":"","cachCoDuoc":"Được lão già Dương Thực cửa đông tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1260","loai":"xuất hiện","importance":"normal","giaiDoan":"Lão già Dương Thực tặng Vương Lâm","text":"Lão già thứ nhất cửa đông tặng Vương Lâm Tụ Lôi Hoàn do lão tự luyện hóa, nén 8900 lần, dùng phòng thân.","anchor":"Đây là Tụ Lôi Hoàn được lão phu tự mình luyện hóa, đã nén lại tám ngàn chín trăm lần, tặng ngươi để phòng thân"}]},"nguon":["@c1260"]},{"id":"ngoc-gian-nhiem-vu-bay-tram-van","name":"Ngọc giản nhiệm vụ (bảy trăm vạn thiên địa)","cn":"","aliases":[],"category":"khac","categoryLabel":"Vật phẩm","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Ngọc giản mà Vương Lâm nhận từ Dương Thực, dùng xác nhận thân phận Vu Phi và làm thông hành vào bảy trăm vạn thiên địa.","detail":"Ngọc giản nhận từ tiểu bối Dương Thực Thiểm Lôi Tộc, chứa lời truyền âm của Hạo Nhiên đạo hữu khen ngợi Vương Lâm. Đưa cho lão tu sĩ cửa Tây xác nhận thân phận. Khi Chu Thiên Tử vào, ngọc giản bùng hào quang chói mắt, Vương Lâm chộp lại dùng để tiến vào bảy trăm vạn thiên địa.","congNang":["Chứng nhận thân phận Vu Phi, làm thông hành vào bảy trăm vạn thiên địa"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1261","denChuong":"","cachCoDuoc":"Nhận từ Dương Thực","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1261","loai":"dùng","importance":"normal","giaiDoan":"Dùng tại cửa Tây","text":"Vương Lâm đưa ngọc giản cho lão tu sĩ cửa Tây xác nhận thân phận Vu Phi, sau đó chộp lại khi ngọc giản bùng hào quang, dùng làm thông hành vào bảy trăm vạn thiên địa.","anchor":"ngọc giản nhiệm vụ bùng ra những luồng hào quang chói mắt bị Vương Lâm chộp vào trong tay"}]},"nguon":["@c1261"]},{"id":"linh-niem-loi","name":"Linh Niệm Lôi","cn":"灵念雷","category":"khac","categoryLabel":"Vật phẩm đặc thù","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Tia chớp nhỏ giống sinh linh, nhìn thấy tồn tại nhưng sờ vào thì vô hình. Bên trong chứa trận pháp sấm sét mạnh ngang lôi trì mười vạn dặm và ý niệm với sinh cơ bừng bừng. Cần thu thập đủ 1000 luồng mới thành niệm lôi hoàn chỉnh.","detail":"Mỗi tộc nhân Thiểm Lôi Tộc lần đầu vào bảy trăm vạn thiên địa được phát một luồng Linh Niệm Lôi. Cả đời chỉ có một cơ hội nhận, mất thì phải cướp hoặc trao đổi lén. Đây là tộc quy phòng ngừa bảo vệ. Vương Lâm nghiên cứu và nhận ra nó giống một sinh linh chứa ý niệm cố chấp đối với sinh mệnh.","congNang":["Thu thập đủ 1000 luồng thành niệm lôi hoàn chỉnh"],"dacDiem":"Vô hình khi chạm, chứa ý niệm sinh linh và trận pháp sấm sét ngang lôi trì mười vạn dặm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1262","denChuong":"","cachCoDuoc":"Được phát khi mạo danh Vu Phi vào bảy trăm vạn thiên địa","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1262","loai":"xuất hiện","importance":"major","giaiDoan":"Phát cho tộc nhân mới đến","text":"Vương Lâm mạo danh Vu Phi nhận Linh Niệm Lôi, nghiên cứu nhận ra nó giống sinh linh chứa ý niệm sinh cơ, cần thu thập đủ 1000 luồng mới thành niệm lôi hoàn chỉnh.","anchor":"Tia chớp này được Vương Lâm cầm trong tay, giống như nó không hẳn là tia chớp mà chính là một sinh linh"}]},"dinhDanh":"goc","capNhatToi":"@c1262","nguon":["@c1262"]},{"id":"phi-kiem-tien-pham-loi-tinh-dien","name":"Phi kiếm tiên phẩm (Lôi Tinh Điện)","cn":"","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tiên phẩm","soHuu":[],"trangThai":"chua-co","blurb":"Bốn thanh phi kiếm tiên phẩm có thể đổi tại Lôi Tinh Điện bằng Linh Niệm Lôi, là mục tiêu nhóm Trương Cảnh Vân lừa người mới thu niệm lôi để gộp đổi lấy.","detail":"Nhóm Trương Cảnh Vân bàn mưu thu niệm lôi của đám người mới, gộp lại thành Linh Niệm Lôi rồi đến Lôi Tinh Điện đổi lấy bốn thanh phi kiếm tiên phẩm.","congNang":["Phi kiếm chiến đấu phẩm cấp tiên phẩm"],"tabs":{"tienTrinh":[{"chuong":"@c1263","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhóm Trương Cảnh Vân nhắc đến khi bàn mưu","text":"Nhóm Trương Cảnh Vân bàn mưu thu niệm lôi của người mới để gộp thành Linh Niệm Lôi, đến Lôi Tinh Điện đổi lấy bốn thanh phi kiếm tiên phẩm.","anchor":"có thể đi đến Lôi Tinh Điện đổi lấy bốn thanh phi kiếm tiên phẩm"}]},"nguon":["@c1263"]},{"id":"linh-niem-loi-dung-hop","name":"Linh Niệm Lôi (dung hợp hoàn chỉnh)","cn":"","category":"nguyen-lieu","categoryLabel":"Nguyên liệu","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"da-dung","blurb":"Gần ngàn luồng Linh Niệm Lôi dung hợp thành một luồng hoàn chỉnh hình quả cầu khói chứa nhiều gương mặt, đã phóng xuyên mắt phải Vương Lâm nhập nguyên thần.","detail":"Gần ngàn luồng Linh Niệm Lôi thu từ tộc ấn Thiểm Lôi Tộc được Vương Lâm vung tay dung hợp thành một luồng duy nhất, hình dạng quả cầu khói xoay tròn bên trong hiện nhiều gương mặt. Khi sấm sét trong nguyên thần Vương Lâm lóe sáng, quả cầu tự phóng xuyên mắt phải dung nhập nguyên thần, hợp nhất với sấm sét, khai mở ký ức lôi bản nguyên từ thuở thiên địa sơ khai. Là loại sấm sét thứ chín trong Cửu đạo lôi.","congNang":["Dung nhập nguyên thần qua mắt phải, hợp nhất sấm sét, khai mở ký ức lôi bản nguyên thái cổ","Tăng trưởng lôi bản nguyên"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1265","denChuong":"","cachCoDuoc":"Dung hợp gần ngàn luồng Linh Niệm Lôi từ tộc ấn Thiểm Lôi Tộc","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1265","loai":"dung","importance":"major","giaiDoan":"Dung hợp và nhập nguyên thần","text":"Gần ngàn Linh Niệm Lôi dung hợp thành một luồng hoàn chỉnh, tự phóng xuyên mắt phải Vương Lâm nhập nguyên thần, khai mở ký ức lôi bản nguyên thái cổ.","anchor":"giống như một làn khói xoay quanh tạo thành hình cầu, trong đó mơ hồ xuất hiện rất nhiều gương mặt"}]},"capNhatToi":"@c1265","dinhDanh":"goc","nguon":["@c1265"]},{"id":"hat-chau-loi-quang","name":"Hạt châu lôi quang","cn":"","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"","soHuu":["Tiên nhân trên kiếp vân"],"trangThai":"hong","blurb":"Pháp bảo do năm luồng niệm lôi hóa thành, ẩn giấu sấm sét uy lực kinh thiên. Bị Vương Lâm bóp nát, năm luồng niệm lôi bị mắt phải hấp thu.","detail":"Hạt châu lôi quang ẩn giấu sấm sét, do năm luồng niệm lôi hóa thành. Thuộc về Tiên nhân Khuy Niết hậu kỳ đại viên mãn trên kiếp vân. Bị Vương Lâm bóp nát, năm luồng niệm lôi nhanh chóng bị mắt phải hấp thu.","congNang":["Ẩn giấu sấm sét, uy lực kinh thiên, do năm luồng niệm lôi hóa thành"],"chuSoHuu":[{"ten":"Tiên nhân trên kiếp vân","tuChuong":"@c1266","denChuong":"@c1266","cachCoDuoc":"Sở hữu ban đầu","trangThai":"tu-vong"},{"ten":"Vương Lâm","tuChuong":"@c1266","denChuong":"","cachCoDuoc":"Bóp nát hấp thu niệm lôi bên trong","trangThai":"da-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1266","loai":"xuat-hien","importance":"normal","giaiDoan":"Xuất hiện và bị phá hủy","text":"Tiên nhân Khuy Niết dùng hạt châu lôi quang tấn công Vương Lâm. Vương Lâm bóp nát, mắt phải hấp thu năm luồng niệm lôi bên trong.","anchor":"Hạt châu lôi quang ẩn giấu sấm sét là pháp bảo do năm luồng niệm lôi hóa thành"}]},"nguon":["@c1266"]},{"id":"linh-phu-huyet-sac","name":"Linh phù huyết sắc","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"đang sử dụng","blurb":"Linh phù do Tán Linh Thượng Nhân tự hủy mấy vạn phân thân ngưng tụ toàn bộ lực lượng mà thành, cho phép mở đường vào bảy trăm vạn thiên địa.","detail":"Tán Linh Thượng Nhân không chút do dự tự hủy mấy vạn phân thân (tu sĩ phân thân trong bảy trăm vạn thiên địa đồng loạt tan vỡ thành máu thịt), ngưng tụ toàn bộ lực lượng thành một linh phù huyết sắc trao cho Vương Lâm. Khi sử dụng, linh phù sẽ phối hợp pháp thuật của Tán Linh bên trong bảy trăm vạn thiên địa, mở con đường đi vào sau ba lần hít thở. Đường này chỉ vào được, không ra được.","congNang":["Mở đường vào bảy trăm vạn thiên địa bị phong ấn sau ba lần hít thở, chỉ vào không ra"],"hinhDang":"Linh phù màu huyết sắc","nguonGoc":"Do Tán Linh Thượng Nhân tự hủy mấy vạn phân thân ngưng tụ","chuHienThoi":"Vương Lâm","chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1268","denChuong":"","cachCoDuoc":"Tán Linh Thượng Nhân trao tặng","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1268","loai":"xuất hiện","importance":"major","giaiDoan":"Tạo ra và trao cho Vương Lâm","text":"Tán Linh Thượng Nhân tự hủy mấy vạn phân thân ngưng tụ toàn bộ lực lượng thành linh phù huyết sắc trao cho Vương Lâm, cho phép mở đường vào bảy trăm vạn thiên địa.","anchor":"Ta tự hủy hai phân thân thì có thể ngưng tụ ra linh phù, dùng linh phù sẽ phối hợp pháp thuật với ta trong đây"}]},"nguon":["@c1268"]},{"id":"loi-sat-kinh","name":"Lôi Sát Kính","cn":"雷杀镜","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Nhị phẩm Thứ Không Niết (tiếp cận Niết phẩm)","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"trangThai":"Đã bị phá hủy","blurb":"Bảo vật trấn tộc Thiểm Lôi Tộc, chiếc gương cổ một mặt có thể phục chế mọi thần thông dưới Đệ Tam Bộ với uy lực ngang bản gốc và phản kích.","detail":"Chiếc gương cổ một mặt màu xanh, mặt sau khắc ký hiệu tia chớp giống sấm sét bất diệt. Được đại trưởng lão Thiểm Lôi Tộc cất giữ trong tộc ấn mi tâm. Công năng cốt lõi là phục chế bất kỳ thần thông nào dưới Đệ Tam Bộ đại năng với uy lực không kém bản gốc, đồng thời phản kích lại người thi triển. Tuy nhiên, lực lượng Cổ Thần nằm ngoài phạm vi phục chế — khi đại trưởng lão dùng Lôi Sát Kính phục chế lôi quyền của Vương Lâm, phần lực lượng Cổ Thần trong đó không thể bị sao chép, khiến bản sao yếu thế. Vương Lâm nương theo đó phun huyết kiếm chém nát Lôi Sát Kính, phá hủy hoàn toàn bảo vật này.","nguon":["@c1270"]},{"id":"van-gioi-phong-hon-tien","name":"Vạn Giới Phong Hồn Tiên","cn":"万界封魂鞭","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (siêu việt mọi phẩm cấp đã biết)","soHuu":["Vị thủ lĩnh tu sĩ thần bí (năm xưa)"],"trangThai":"Đã bị mang đi (bản gốc); Côn Cực Tiên của Vương Lâm là bản mô phỏng","blurb":"Bản gốc của Côn Cực Tiên, pháp bảo do vị thủ lĩnh đám tu sĩ thần bí năm xưa sử dụng, vung ba roi tạo ra bảy trăm vạn thiên địa.","detail":"Tên thật của cây roi mà vị thủ lĩnh nhóm tu sĩ thần bí sử dụng thời khai thiên. Trong hồi ức của đại trưởng lão Thiểm Lôi Tộc (khi còn là tu sĩ Hóa Thần): roi thứ nhất làm thiên địa tan vỡ, tinh không xuất hiện khe nứt, tạo ra bảy trăm vạn thiên địa; roi thứ hai phá vỡ hư vô, cuốn lấy vài sinh linh đặt vào bảy trăm vạn thiên địa (nhóm người đầu tiên); roi thứ ba đánh tan hình bóng khủng bố lao ra từ hư vô. Sau đó đám tu sĩ mang roi đi. Bản chất là vài tỷ hồn phách sinh linh dung hợp tạo thành, chuyên đánh nguyên thần và hồn phách. Côn Cực Tiên hiện tại của Vương Lâm là bản mô phỏng, không phải bản gốc — lớp ngoài u quang là vỏ bọc, khi vỡ lộ ra bản thể kim quang mang uy áp tương tự nhưng yếu hơn bản gốc.","nguon":["@c1270"]},{"id":"la-ban-sinh-menh-than-thong","name":"La bàn khổng lồ (Sinh Mệnh Thần Thông)","cn":null,"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (pháp khí tế tổ)","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"trangThai":"Triệu hoán khi thi triển Sinh Mệnh Thần Thông, biến mất sau khi hấp thu thọ nguyên","blurb":"La bàn vô biên vô hạn xuất hiện khi đại trưởng lão Thiểm Lôi Tộc thi triển Sinh Mệnh Thần Thông, hấp thu 500 năm thọ nguyên làm vật dẫn tế tổ rút sấm sét bất diệt.","detail":"La bàn khổng lồ vô biên vô hạn, bùng ra khí tức tang thương muôn đời, bên ngoài bị phá hoại nhiều chỗ như từng trải qua đại chiến. Xuất hiện khi đại trưởng lão thi triển Sinh Mệnh Thần Thông — hy sinh 500 năm thọ nguyên, la bàn hấp thu toàn bộ sinh cơ tản ra rồi biến mất, sau đó một luồng sấm sét bất diệt từ miếu thờ thánh địa được rút ra tấn công, phá tan bảy vạn tầng lưới sấm sét của Vương Lâm trong nháy mắt. Các tinh vực ngoài Thiểm Lôi Tộc đều có thể nhìn thấy la bàn này khi nó xuất hiện.","nguon":["@c1270"]},{"id":"bo-giap-sam-set-bat-diet","name":"Bộ giáp sấm sét bất diệt","cn":null,"aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Bảo vật truyền thừa Đệ Tam Bộ (vượt xa Lôi Sát Kính)","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"trangThai":"Bị phá hủy hoàn toàn","blurb":"Bảo vật truyền thừa Đệ Tam Bộ Thiểm Lôi Tộc, bộ giáp phòng ngự mạnh vượt xa Lôi Sát Kính, bị kiếm thứ nhất của Trảm Thiên kiếm phá hủy hoàn toàn.","detail":"Bộ giáp sấm sét bất diệt là bảo vật truyền thừa của Đệ Tam Bộ Thiểm Lôi Tộc, phẩm cấp vượt xa Lôi Sát Kính. Đại trưởng lão Thiểm Lôi Tộc mặc giáp này trong trận chiến tại bảy trăm vạn thiên địa. Khi Vương Lâm cầm Trảm Thiên kiếm chém kiếm thứ nhất — kiếm quang mang theo linh hồn sinh linh — bộ giáp bị phá hủy hoàn toàn, đại trưởng lão lộ ra ba vết thương trước ngực lộ xương trắng.","nguon":["@c1271"]},{"id":"tieu-cau-huong-hoa","name":"Tiểu cầu hương hỏa","cn":null,"aliases":[],"category":"khac","categoryLabel":"Khác","phamCap":"Không rõ","soHuu":["Vương Lâm"],"trangThai":"Đã sử dụng","blurb":"Tiểu cầu ngưng tụ từ toàn bộ lực lượng hương hỏa mà Vương Lâm rút ra khi diệt hồn phách trong Hô Phong Hoán Vũ, dùng để phá vỡ vòng xoáy Lục Đạo Thần Lôi.","detail":"Vương Lâm ra lệnh tất cả hồn phách trong Hô Phong Hoán Vũ diệt hồn dâng hiến lực lượng hương hỏa — bao gồm cả viễn cổ tiên phi bạch y nữ tử, nguồn hương hỏa lớn nhất. Lực lượng hương hỏa ngưng tụ thành tiểu cầu, là lực lượng đặc trưng của Đệ Tam Bộ đại năng, khiến đại trưởng lão Thiểm Lôi Tộc kinh hoàng. Vương Lâm ném tiểu cầu phá vỡ vòng xoáy Lục Đạo Thần Lôi, sau đó diệt toàn bộ hồn phách còn lại để bùng ra đợt hương hỏa thứ hai, tiêu diệt hoàn toàn Lục Đạo Thần Lôi.","nguon":["@c1271"]},{"id":"tram-thien-kiem","name":"Trảm Thiên kiếm","cn":"斩天剑","aliases":[],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Không rõ (ngưng tụ từ Tuyệt Thiên trận + tính mạng hàng tỷ sinh linh)","soHuu":["Vương Lâm"],"trangThai":"Đang sử dụng","blurb":"Trường kiếm do Tán Linh ngưng tụ từ Tuyệt Thiên trận phong ấn bát hoang, chứa hy vọng và sinh mệnh của tất cả sinh linh bảy trăm vạn thiên địa, giao cho Vương Lâm thi triển Thất Kiếm Trảm Thiên Sơn.","detail":"Trảm Thiên kiếm được Tán Linh Thượng Nhân ngưng tụ khi dung hợp vào đại trận Tuyệt Thiên trận phong ấn bát hoang — lấy tính mạng tất cả sinh linh (hàng tỷ phàm nhân và tu sĩ) trên bảy trăm vạn thiên địa làm nguồn lực. Kiếm chính là trường kiếm bảy thước, chứa hy vọng của toàn bộ sinh linh tình nguyện hy sinh. Tán Linh nói đây là “bảy phần nắm chắc” hắn đã hứa trước. Mỗi kiếm chém ra, sinh linh bảy trăm vạn thiên địa dâng tính mệnh, nhiều người tử vong — kiếm thứ nhất phá hủy bộ giáp sấm sét bất diệt, các kiếm tiếp theo khiến đại trưởng lão Thiểm Lôi Tộc trọng thương liên tiếp. Vương Lâm cảm nhận kiếm rất nặng vì chứa sinh mệnh người tình nguyện hy sinh, linh hồn được gột rửa dưới âm thanh đau thương. Đến kiếm thứ sáu, uy lực khiến biên giới bảy trăm vạn thiên địa tan vỡ thành từng mảng, tinh không nứt rạn.","nguon":["@c1271"]},{"id":"thiem-loi-an","name":"Thiểm Lôi ấn","cn":null,"aliases":["Tộc ấn trên mi tâm"],"category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Tộc ấn truyền thừa Thiểm Lôi Tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"trangThai":"Nổ hơn một nửa","blurb":"Tộc ấn trên mi tâm đại trưởng lão Thiểm Lôi Tộc, vỗ vào để triệu hồi Lục Đạo Thần Lôi và hóa thành thuật Đệ Tam Bộ — sấm sét âm dương bất diệt.","detail":"Tộc ấn nằm trên mi tâm đại trưởng lão Thiểm Lôi Tộc, là vật truyền thừa chứa lực lượng tộc nhân. Đại trưởng lão vỗ vào tộc ấn để triệu hồi Lục Đạo Thần Lôi (sáu loại sấm sét truyền thừa qua các thế hệ). Sau đó kích nổ một nửa tộc ấn để triệu hồi sấm sét bất diệt bên ngoài tấn công gió bão. Đại trưởng lão còn dâng 3.000 năm thọ nguyên hóa Thiểm Lôi ấn thành thuật Đệ Tam Bộ — Âm Dương đồ phân ra hai luồng sấm sét phá nguyên thần và thân thể. Đến cuối trận, tộc ấn đã nổ hơn một nửa.","nguon":["@c1271"]},{"id":"sam-set-bat-diet","name":"Sấm sét bất diệt","cn":"不灭雷电","category":"than-khi","categoryLabel":"Thần khí","phamCap":"Thánh vật Thiểm Lôi tộc","soHuu":["Thiểm Lôi tộc"],"trangThai":"trong-thuong","blurb":"Thánh vật của Thiểm Lôi tộc, luồng sấm sét bất diệt có linh trí, uy lực ngang ngửa trường kiếm ngưng tụ lực toàn bộ bảy trăm vạn thiên địa.","detail":"Sấm sét bất diệt là thánh vật Thiểm Lôi tộc, có linh trí và đáp ứng tiếng gọi nô bộc. Khi đại trưởng lão Thiểm Lôi tộc gầm gọi cứu viện, sấm sét bất diệt phóng to thành thần lôi vạn trượng phá vỡ phong ấn gió bão do Tán Linh thượng nhân duy trì. Sau đó phóng vào bảy trăm vạn thiên địa đối đầu trường kiếm bảy thước, uy lực ngang ngửa. Cả hai cùng tổn thương: trường kiếm tan vỡ, sấm sét bất diệt bị trọng thương rút về miếu thờ thánh địa Thiểm Lôi tộc. Mười sáu tu chân tinh anh mở đại trận phong tỏa bảo vệ.","hinhDang":"Luồng sấm sét, có thể phóng to thành thần lôi vạn trượng","nguonGoc":"Thánh vật của Thiểm Lôi tộc","dacDiem":"Có linh trí, đáp ứng tiếng gọi, uy lực ngang trường kiếm ngưng tụ lực toàn bộ bảy trăm vạn thiên địa","congNang":["Phá phong ấn cấp cao","Đối đầu kiếm khí cấp tiên","Hóa thần lôi vạn trượng"],"chuSoHuu":[{"ten":"Thiểm Lôi tộc","tuChuong":"@c1272","denChuong":"","cachCoDuoc":"Thánh vật bộ tộc","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1272","loai":"dùng","importance":"major","giaiDoan":"Đối đầu trường kiếm bảy thước, bị trọng thương","phamCap":"Thánh vật","text":"Nghe tiếng gọi đại trưởng lão, hóa thần lôi vạn trượng phá vỡ phong ấn gió bão. Phóng vào bảy trăm vạn thiên địa đối đầu trường kiếm bảy thước, cả hai cùng tổn thương. Bị trọng thương rút về miếu thờ thánh địa.","anchor":"luồng sấm sét bất diệt chợt phóng vào trong trời đất bảy trăm vạn thiên địa"}]},"nguon":["@c1272"]},{"id":"toc-an-thiem-loi-toc-vat","name":"Tộc ấn (Thiểm Lôi tộc)","category":"phap-bao","categoryLabel":"Pháp bảo","phamCap":"Ấn ký bộ tộc","soHuu":["Đại trưởng lão Thiểm Lôi Tộc"],"trangThai":"hong","blurb":"Tộc ấn trên mi tâm nguyên thần đại trưởng lão Thiểm Lôi tộc, khi tự bạo giải phóng lực lượng tương đương tu sĩ Nội giới tự bạo.","detail":"Tộc ấn nằm trên mi tâm nguyên thần của đại trưởng lão Thiểm Lôi tộc. Khi bị dồn vào đường cùng, đại trưởng lão cho nổ tộc ấn, lực lượng giải phóng tương đương tu sĩ Nội giới tự bạo, giết sạch oan hồn bao quanh, tu vi tăng vọt tạm thời và thân thể sấm sét tái tạo. Tuy nhiên tu sĩ Thái Cổ Tinh Thần có điểm khác nên không chết ngay sau khi nổ.","congNang":["Tự bạo giải phóng lực lượng khổng lồ tương đương Nội giới tự bạo","Tu vi tăng vọt tạm thời"],"chuSoHuu":[{"ten":"Đại trưởng lão Thiểm Lôi Tộc","tuChuong":"@c1272","denChuong":"@c1272","cachCoDuoc":"Ấn ký bộ tộc sẵn có","trangThai":"hong"}],"tabs":{"tienTrinh":[{"chuong":"@c1272","loai":"dùng","importance":"major","giaiDoan":"Tự bạo trong trận chiến","text":"Đại trưởng lão cho nổ tộc ấn trên mi tâm nguyên thần trong cơn tuyệt vọng, giết sạch oan hồn, tu vi tăng vọt, thân thể sấm sét tái tạo.","anchor":"tộc ấn trên mi tâm nguyên thần đã nổ ầm ầm"}]},"nguon":["@c1272"]},{"id":"nguyen-than-dai-truong-lao-thiem-loi-toc","name":"Nguyên thần đại trưởng lão Thiểm Lôi tộc","cn":"","category":"khac","categoryLabel":"Vật phẩm đặc biệt","phamCap":"Thiên Nhân Đệ Ngũ Suy","soHuu":["Vương Lâm"],"trangThai":"dang-co","blurb":"Nguyên thần Thiên Nhân Đệ Ngũ Suy bị tàn phá hơn phân nửa, trí nhớ tiêu tán, Vương Lâm thu lại bằng Côn Cực Tiên. Chứa cảm ngộ sấm sét, có thể dùng Tát Đậu Thành Binh, được đánh giá là cơ hội tạo hóa.","detail":"Nguyên thần đại trưởng lão Thiểm Lôi tộc bị kiếm khí gây thương tích trước đó rồi bị trùng kích sấm sét bất diệt và trường kiếm bảy thước đánh tan hơn phân nửa, sắp tiêu tán. Vương Lâm dùng Côn Cực Tiên hóa roi kim quang quét lại, chụp vào tay. Nguyên thần chứa cảm ngộ sấm sét cả đời tu sĩ Thiên Nhân Đệ Ngũ Suy, có thể khai thác hoặc dùng Tát Đậu Thành Binh tạo binh sĩ cực hùng mạnh.","congNang":["Dùng Tát Đậu Thành Binh tạo binh sĩ cực hùng mạnh","Khai thác cảm ngộ sấm sét của Thiên Nhân Đệ Ngũ Suy"],"chuSoHuu":[{"ten":"Vương Lâm","tuChuong":"@c1273","denChuong":"","cachCoDuoc":"Thu bằng Côn Cực Tiên sau khi đánh bại","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1273","loai":"đổi chủ","importance":"normal","giaiDoan":"Vương Lâm thu nguyên thần","text":"Nguyên thần bị tàn phá hơn phân nửa, sắp tiêu tán. Vương Lâm dùng Côn Cực Tiên hóa roi kim quang quét lại và chụp vào tay, đánh giá là cơ hội tạo hóa.","anchor":"nguyên thần của đại trưởng lão Thiểm Lôi tộc có thể so sánh với những bảo vật cực kỳ quý giá"}]},"capNhatToi":"@c1273","nguon":["@c1273"]}]};
